            //format += "<fc> id=crn 			name=사업자번호  width=100 align=left sort=true suppress=2 </fc>";
            //format += "<fc> id=clntNo 		name=거래처코드	 width=90 align=left sort=true suppress=1 </fc>";
            showCols.push("crn");
            showCols.push("clntNo");
        } else {//사업자번호기준
            //format += "<fc> id=crn 			name=사업자번호  width=100 align=left sort=true </fc>";
            //format += "<fc> id=clntNo 		name=거래처코드	 width=90 align=left sort=true show=false </fc>";
            showCols.push("crn");
            hideCols.push("clntNo");
        }
        //format += "<fc> id=clntNm			name=거래처  width=210 align=left sort=true subSumText='소계' sumtext='합계' Cursor=Hand </fc>";
        showCols.push("clntNm");
    }	

    if (lc_srchBookClsCd.getText(true) == "요약") {
        //format += "<c> id=sellAmt              name=실적매출 	 width=90 align=right sort=true dec=0 sumText=@sum </c>";
        //format += "<c> id=varCostAmt           name=실적매입         width=90 align=right sort=true dec=0 sumText=@sum </c>";
        showCols.push("sellAmt");
        showCols.push("varCostAmt");

        hideCols.push("sellDcsnAmt");
        hideCols.push("sellUnAmt");
        hideCols.push("sellInAmt");
        hideCols.push("pchsInAmt");
        hideCols.push("pchsDcsnAmt");
        hideCols.push("pchsUnAmt");
        hideCols.push("pchsDistAmt");
        hideCols.push("pchsCtrlAmt");
    } else {
        // format += "<c> id=sellDcsnAmt          name=확정매출 	 width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=sellUnAmt            name=미확정매출	 width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=sellInAmt            name=내부매출	 width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=pchsInAmt            name=내부매입	 width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=sellAmt              name=실적매출 	 width=90 align=right sort=true dec=0 sumText=@sum HeadBgColor='#FFE08C' BgColor='#FFE08C' </c>";
        // format += "<c> id=pchsDcsnAmt          name=확정매입         width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=pchsUnAmt            name=미확정매입      width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=pchsDistAmt          name=배부매입        width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=pchsCtrlAmt          name=조정매입        width=90 align=right sort=true dec=0 sumText=@sum </c>";
        // format += "<c> id=varCostAmt           name=실적매입         width=90 align=right sort=true dec=0 sumText=@sum HeadBgColor='#FFE08C' BgColor='#FFE08C' </c>";
        showCols.push("sellAmt");
        FFE08CCols.push("sellAmt");
        showCols.push("varCostAmt");
        FFE08CCols.push("varCostAmt");

        showCols.push("sellDcsnAmt");
        showCols.push("sellUnAmt");
        showCols.push("sellInAmt");
        showCols.push("pchsInAmt");
        showCols.push("pchsDcsnAmt");
        showCols.push("pchsUnAmt");
        showCols.push("pchsDistAmt");
