        gr_ProfitAndLoss.setColumnBackgroundColor(colId, "#FFE08C");
    });
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(){
    let ret;
    // 필수사항 체크
    ret = await $c.gus.cfValidate([ed_pCloseYm, ed_pBizDomCd]);
    if (!ret) {
        return;
    }
    let str = ed_pCloseYm.getValue();
    str = str.substring(0,4) + "년 " + str.substring(4,6) + "월 사업영역 [" + ed_pBizDomNm.getValue() +  "]";

    ret = await $c.win.confirm(str + " 거래처 손익실적을 생성하시겠습니까?");
    if ( !ret ) {
        return;
    }  

    // dma_search 데이터맵에 각 컨트롤의 값을 세팅합니다.
    dma_search.setJSON({
        "bookClsCd"        : lc_srchBookClsCd.getValue(),      // 장부구분
        "closeYmSt"        : ed_closeYmSt.getValue(),          // 기준년월_시작
        "closeYmEnd"       : ed_closeYmEnd.getValue(),         // 기준년월_종료
        "acctDeptCd"       : ed_acctDeptCd.getValue(),         // 부서코드
        "clntNo"           : ed_clntNo.getValue(),             // 거래처코드
        "bizDomCd"         : ed_BizDomCd.getValue(),           // 사업영역코드
        "schGroup"         : rd_schGroup.getValue(),           // 집계기준
        "crn"              : ed_crn.getValue(),                // 사업자번호
        "transCargoClsCd"  : rd_transCargoClsCd.getValue(),    // 구분
        "pCloseYm"         : ed_pCloseYm.getValue(),           // 기준년월_프로시저
        "pBizDomCd"        : ed_pBizDomCd.getValue()           // 사업영역코드_프로시저
    });

    $c.sbm.execute(sbm_create);
}

scwin.udc_BizDomCd_cb = function(rtnList) {
    if ( rtnList != null ) {
        if (rtnList[0] == "N/A") return;

        if (scwin._gb == "1") {//검색조건
            ed_BizDomCd.setValue( rtnList[0] );	    // 코드
            ed_BizDomNm.setValue( rtnList[1] );	// 코드명
        } else {//생성조건
            ed_pBizDomCd.setValue( rtnList[0] );	    // 코드
            ed_pBizDomNm.setValue( rtnList[1] );	// 코드명
        }
    } else {
        if (scwin._gb == "1") {//검색조건
            ed_BizDomCd.setValue("");	    	// 코드
            ed_BizDomNm.setValue("");	    // 코드명
        } else {//생성조건
            ed_pBizDomCd.setValue("");	    	// 코드
            ed_pBizDomNm.setValue("");	    // 코드명
        }
    }
}

//-------------------------------------------------------------------------
// 사업영역코드팝업
//-------------------------------------------------------------------------
scwin.f_BizDomPopUp = function(_gb) {

    let sCmdName = "";
    let param = "";
    scwin._gb = _gb;

    sCmdName = "retrieveBizDomCdInfo";

    if (_gb == "1") {//검색조건
        cd = ed_BizDomCd.getValue();
        nm = "";
    } else {
        cd = ed_pBizDomCd.getValue();
        nm = "";
    }
    param    = ",,,";

    udc_BizDomCd.setSelectId(sCmdName);
    udc_BizDomCd.cfCommonPopUp(
        scwin.udc_BizDomCd_cb,cd,nm,'T',null,null,null,null,param,null,null,null,null,null,"F",null,null); // 거래처
}

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function(){
    if ( await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {

        let sheetTitle = "거래처별손익실적_" + ed_closeYmSt.getValue().trim() + "_" + ed_closeYmEnd.getValue().trim();
        const gridId = gr_ProfitAndLoss;
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xls",    // + ".xls",
            sheetName: sheetTitle
        };

        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
}

// 그리드의 단위를 변경한다.
scwin.f_changeUnit = function() {
    if ( lc_unit.getValue() == "01" ) {
        scwin.f_changeUnitAmt(1);
    } else if ( lc_unit.getValue() == "02" ) {
        scwin.f_changeUnitAmt(1000);
    } else if ( lc_unit.getValue() == "03" ) {
        scwin.f_changeUnitAmt(1000000);
    } else if ( lc_unit.getValue() == "04" ) {
        scwin.f_changeUnitAmt(100000000);
    }
}

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function (unitAmt) {

    if (!ds_master_org || ds_master_org.getRowCount() === 0) {
        return;
    }

    // 원본 기준으로 항상 다시 계산
    let calculatedData = ds_master_org.getAllJSON();

    const cols = [
        "sellDcsnAmt", "sellUnAmt", "sellInAmt", "sellAmt",
        "pchsInAmt", "pchsDcsnAmt", "pchsUnAmt", "pchsDistAmt", "pchsCtrlAmt",
        "varCostAmt",
        "marginalProfits", "directFixCostAmt", "directProfits",
        "fixCostAmt", "sellSumAmt", "saleCostAmt", "businessProfits"
    ];

    for (let i = 0; i < calculatedData.length; i++) {
        let row = calculatedData[i];

        for (let col of cols) {
            let val = Number(row[col] || 0);
            row[col+"_org"] = val;
            row[col] = Math.round(val / unitAmt);
        }
    }

    ds_master.setJSON(calculatedData);
};

//거래처손익실적 상세팝업
scwin.f_detail = function() {

    if ( ed_BizDomCd.getValue() == "" ) {
        $c.win.alert("상세내역은 사업영역 조회조건 필수입니다.\n재조회 후 확인하세요.");
        return;
    }
    if (ds_master.getCellData(ds_master.getRowPosition(),"crn") == "") {
        return;
    }

    let data = {};

    data.closeYmSt = ed_closeYmSt.getValue();
    data.closeYmEnd = ed_closeYmEnd.getValue();
    data.bizDomCd = ed_BizDomCd.getValue();
    data.acctDeptCd = ed_acctDeptCd.getValue();
    data.crn = ds_master.getCellData(ds_master.getRowPosition(),"crn");
    data.clntNo = ds_master.getCellData(ds_master.getRowPosition(),"clntNo");
    data.schGroup = rd_schGroup.getValue();
    data.transCargoClsCd = rd_transCargoClsCd.getValue();

    //var sURL = "/ac/co/rsltsmgnt/rsltsanl/co_404_01_51p.jsp";
    //var rtnList = window.showModelessDialog(sURL, shcParam,"dialogWidth:1220px; dialogHeight:680px; scroll:yes;resizable:yes;status:no;");

    const options = {
        id: "co_404_01_51p",
        type: "browserPopup",
        modal : true ,
        popupName:"거래처별손익실적_상세",
        width: 1500,
        height: 800
    };
    $c.win.openPopup("/ui/ac/co/rsltsmgnt/rsltsanl/co_404_01_51p.xml",options,data);
}

